// Extrai e sanitiza os parâmetros de busca
const body = $input.item.json.body || {};
const query = {
  q: body.query || body.q || '',
  categoryId: body.categoryId || null,
  brand: body.brand || null,
  minPrice: body.minPrice || null,
  maxPrice: body.maxPrice || null,
  inStock: body.inStock !== false,
  page: body.page || 1,
  pageSize: Math.min(body.pageSize || 10, 20),
  storeId: body.storeId || '',
  tenantId: body.tenantId || ''
};

// Monta query string
const params = Object.entries(query)
  .filter(([_, v]) => v !== null && v !== '')
  .map(([k, v]) => `${k}=${encodeURIComponent(v)}`)
  .join('&');

return { params, query };

// Formata a lista de produtos para resposta ao cliente
const products = $json.items || [];
const isAlternatives = false;

const formatted = products.map((p, i) => ({
  index: i + 1,
  id: p.id,
  sku: p.sku,
  name: p.name,
  brand: p.brand,
  price: p.price,
  promotionalPrice: p.promotionalPrice,
  stock: p.stock,
  unit: p.unit,
  category: p.category?.name,
  imageUrl: p.images?.[0]?.url,
  shortDescription: p.shortDescription
}));

return {
  products: formatted,
  total: $json.totalCount || formatted.length,
  hasMore: ($json.page || 1) < ($json.totalPages || 1)
};
